// Traite TOUS les items de la boucle
const items = $input.all();

return items.map(item => {
  // Cherche le HTML pour cet item
  const htmlData = item.json.html || item.json.data || '';

  // Si pas de HTML valide, skip
  if (!htmlData || htmlData.length < 100) {
    return {
      json: {
        ...item.json,
        cleanText: "No valid website content available"
      }
    };
  }

  // Nettoie le HTML
  const cleanText = htmlData
    .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
    .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
    .replace(/<head[^>]*>[\s\S]*?<\/head>/gi, '')
    .replace(/<nav[^>]*>[\s\S]*?<\/nav>/gi, '')
    .replace(/<footer[^>]*>[\s\S]*?<\/footer>/gi, '')
    .replace(/<svg[^>]*>[\s\S]*?<\/svg>/gi, '')
    .replace(/<!--[\s\S]*?-->/g, '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&[a-z]+;/gi, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .substring(0, 2000);

  return {
    json: {
      ...item.json,
      cleanText: cleanText
    }
  };
});

// Récupère les données du webhook
const webhookData = $('Webhook').item.json.body || {};
const targetCount = webhookData.targetCount || 10;

// Compte combien de drafts ont été créés lors de CETTE exécution
const draftsCreated = $('Create a draft').all().length;

// Pour simplifier : on suppose qu'on relance toujours
// (Le frontend arrêtera quand le quota sera atteint)
return [{
  json: {
    draftsCreated: draftsCreated,
    targetCount: targetCount,
    shouldRetry: true, // Toujours relancer (le frontend gère le stop)
    webhookData: webhookData
  }
}];

const text = $input.item.json.output;

let parsedOutput;

try {
  const cleanedText = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  parsedOutput = JSON.parse(cleanedText);

  return {
    json: {
      subject: parsedOutput.subject,
      body: parsedOutput.body
    }
  };

} catch (error) {
  return {
    json: {
      subject: "Error parsing subject",
      body: text
    }
  };
}

// Données pour le lead (email, draft = sujet + corps)
const emailTo = $('Extract Email (from HTML)').item.json.email || $('Split Out').item.json.email;
const emailSubject = $json.subject || 'Nouveau message';
const emailBody = $json.body || '';

return {
  json: {
    emailTo,
    emailSubject,
    emailBody,
  }
};
